CREATE MATERIALIZED VIEW public.files_mv AS
 SELECT fe.id AS file_id,
    ffc.files_id,
    ue.id AS upload_id,
    ue.file_path,
    ue.mime_type,
    ue.size,
    fe.created_at
   FROM ((((public.files_entry fe
     JOIN public.file_files_connection ffc ON (((ffc.file_id = fe.id) AND (ffc.active = true))))
     JOIN public.files_resource fr ON (((fr.id = ffc.files_id) AND (fr.active = true))))
     JOIN public.file_uploads_entry fue ON (((fue.file_id = fe.id) AND (fue.active = true))))
     JOIN public.uploads_entry ue ON (((ue.id = fue.upload_id) AND (ue.active = true))))
  WHERE (fe.active = true)
  WITH NO DATA;


